{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "properties": {
    "subscriptionId": {
      "type": "string",
      "description": "Unique identifier for the subscription"
    },
    "customerId": {
      "type": "string",
      "description": "Unique identifier for the customer"
    },
    "invoiceId": {
      "type": "string",
      "description": "Unique identifier for the invoice"
    },
    "amount": {
      "type": "number",
      "description": "Amount due for payment"
    },
    "currency": {
      "type": "string",
      "description": "Currency code (ISO 4217)"
    },
    "dueDate": {
      "type": "string",
      "format": "date-time",
      "description": "When the payment is due"
    },
    "billingPeriod": {
      "type": "object",
      "properties": {
        "start": {
          "type": "string",
          "format": "date"
        },
        "end": {
          "type": "string",
          "format": "date"
        }
      },
      "required": ["start", "end"]
    },
    "planId": {
      "type": "string",
      "description": "Subscription plan identifier"
    },
    "retryAttempt": {
      "type": "integer",
      "description": "Number of retry attempts for failed payments"
    }
  },
  "required": ["subscriptionId", "customerId", "invoiceId", "amount", "currency", "dueDate"]
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "InvoiceGenerated",
  "description": "Schema for invoice generated event",
  "properties": {
    "invoiceId": {
      "type": "string",
      "description": "Unique identifier for the invoice"
    },
    "invoiceNumber": {
      "type": "string",
      "description": "Human-readable invoice number"
    },
    "subscriptionId": {
      "type": "string",
      "description": "Unique identifier for the subscription"
    },
    "customerId": {
      "type": "string",
      "description": "Unique identifier for the customer"
    },
    "invoiceDate": {
      "type": "string",
      "format": "date-time",
      "description": "Date and time when the invoice was generated"
    },
    "dueDate": {
      "type": "string",
      "format": "date-time",
      "description": "Date and time when the invoice payment is due"
    },
    "status": {
      "type": "string",
      "enum": ["generated", "sent", "paid", "overdue", "cancelled"],
      "description": "Current status of the invoice"
    },
    "lineItems": {
      "type": "array",
      "description": "List of items on the invoice",
      "items": {
        "type": "object",
        "properties": {
          "description": {
            "type": "string",
            "description": "Description of the line item"
          },
          "quantity": {
            "type": "number",
            "description": "Quantity of the item"
          },
          "unitPrice": {
            "type": "number",
            "description": "Price per unit"
          },
          "total": {
            "type": "number",
            "description": "Total price for this line item (quantity * unitPrice)"
          }
        },
        "required": ["description", "quantity", "unitPrice", "total"]
      }
    },
    "subtotal": {
      "type": "number",
      "description": "Subtotal amount before taxes"
    },
    "tax": {
      "type": "number",
      "description": "Tax amount applied to the invoice"
    },
    "total": {
      "type": "number",
      "description": "Total amount including taxes"
    },
    "currency": {
      "type": "string",
      "description": "Currency code (ISO 4217)"
    },
    "billingPeriod": {
      "type": "object",
      "description": "Billing period covered by this invoice",
      "properties": {
        "start": {
          "type": "string",
          "format": "date",
          "description": "Start date of the billing period"
        },
        "end": {
          "type": "string",
          "format": "date",
          "description": "End date of the billing period"
        }
      },
      "required": ["start", "end"]
    },
    "planId": {
      "type": "string",
      "description": "Subscription plan identifier"
    }
  },
  "required": [
    "invoiceId",
    "invoiceNumber",
    "subscriptionId",
    "customerId",
    "invoiceDate",
    "dueDate",
    "status",
    "lineItems",
    "subtotal",
    "tax",
    "total",
    "currency",
    "billingPeriod",
    "planId"
  ]
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "PaymentProcessed",
  "description": "Event triggered after a payment has been successfully processed",
  "properties": {
    "transactionId": {
      "type": "string",
      "format": "uuid",
      "description": "Unique identifier for the payment transaction"
    },
    "userId": {
      "type": "string",
      "format": "uuid",
      "description": "Unique identifier of the user who made the payment"
    },
    "orderId": {
      "type": "string",
      "format": "uuid",
      "description": "Unique identifier of the associated order"
    },
    "amount": {
      "type": "number",
      "description": "The payment amount"
    },
    "currency": {
      "type": "string",
      "description": "Currency code (ISO 4217)",
      "default": "USD"
    },
    "paymentMethod": {
      "type": "string",
      "enum": ["CreditCard", "DebitCard", "BankTransfer", "PayPal", "Crypto"],
      "description": "The payment method used"
    },
    "status": {
      "type": "string",
      "enum": ["confirmed", "pending", "failed"],
      "description": "The outcome status of the payment"
    },
    "subscriptionId": {
      "type": "string",
      "description": "Subscription identifier, if payment is subscription-related"
    },
    "paymentId": {
      "type": "string",
      "format": "uuid",
      "description": "Unique identifier for the payment record"
    },
    "confirmationDetails": {
      "type": "object",
      "description": "Details from the payment gateway",
      "properties": {
        "gatewayResponse": {
          "type": "string",
          "description": "Response from the payment gateway"
        },
        "transactionId": {
          "type": "string",
          "description": "Gateway-specific transaction identifier"
        }
      },
      "required": ["gatewayResponse", "transactionId"]
    },
    "timestamp": {
      "type": "string",
      "format": "date-time",
      "description": "Timestamp when the payment was processed"
    }
  },
  "required": ["transactionId", "userId", "orderId", "amount", "currency", "paymentMethod", "status", "paymentId", "confirmationDetails", "timestamp"]
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "properties": {
    "paymentId": {
      "type": "string",
      "description": "Unique identifier for the failed payment"
    },
    "amount": {
      "type": "number",
      "description": "Payment amount that failed"
    },
    "currency": {
      "type": "string",
      "description": "Currency code (ISO 4217)"
    },
    "failureReason": {
      "type": "string",
      "enum": [
        "insufficient_funds",
        "card_declined",
        "expired_card",
        "fraud_suspected",
        "network_error",
        "invalid_payment_method",
        "authentication_required",
        "other"
      ],
      "description": "Reason for payment failure"
    },
    "failureMessage": {
      "type": "string",
      "description": "Human-readable failure message"
    },
    "metadata": {
      "type": "object",
      "properties": {
        "subscriptionId": {
          "type": "string"
        },
        "invoiceId": {
          "type": "string"
        },
        "customerId": {
          "type": "string"
        },
        "orderId": {
          "type": "string"
        }
      }
    },
    "canRetry": {
      "type": "boolean",
      "description": "Whether this payment can be retried"
    },
    "nextRetryAt": {
      "type": "string",
      "format": "date-time",
      "description": "Suggested time for next retry attempt"
    },
    "timestamp": {
      "type": "string",
      "format": "date-time",
      "description": "When the failure occurred"
    }
  },
  "required": ["paymentId", "amount", "currency", "failureReason", "timestamp"]
}

syntax = "proto3";

package com.example.frauddetection;

message FraudCheckCompleted {
  string transactionId = 1;
  string paymentId = 2;
  int32 riskScore = 3;
  string decision = 4;
  repeated string reasons = 5;
  double confidence = 6;
  string timestamp = 7;
}

message FraudCheckCompletedEvent {
  FraudCheckCompleted fraudCheckCompleted = 1;
}

